"""
server.py
Scale Brain HTTP server - Microdot-based REST API + static file serving.

Endpoints:
  GET  /                          - serve index.html
  GET  /style.css                 - serve stylesheet
  GET  /app.js                    - serve frontend JS

  GET  /api/weight                - current weight reading + scale state
  POST /api/tare                  - zero the scale
  POST /api/hold                  - toggle hold mode { "active": true/false }
  POST /api/calibrate             - calibrate with known weight { "weight_g": 1000 }
  GET  /api/debug                 - raw diagnostic values

  GET  /api/config                - scale config (units, cal_factor, keglevel_url, wifi, version)
  PUT  /api/config                - update config

  GET  /api/profiles              - list saved profiles
  POST /api/profiles              - create profile
  PUT  /api/profiles/<id>         - update profile
  DELETE /api/profiles/<id>       - delete profile

  GET  /api/keglevel/kegs         - proxy: fetch kegs from KegLevel
  PUT  /api/keglevel/kegs/<id>    - proxy: update keg on KegLevel

  POST /api/update                - OTA: write file to flash
  GET  /api/ota/manifest          - OTA: read installed manifest
  PUT  /api/ota/manifest          - OTA: write installed manifest

  GET  /api/version               - firmware version
"""

import asyncio
import gc
import json
import os
import time
import machine

from microdot import Microdot, Request

Request.max_content_length = 32 * 1024

import config_manager
import scale
from version import FIRMWARE_VERSION, BUILD_DATE

app = Microdot()

_boot_ticks = time.ticks_ms()


# ---------------------------------------------------------------------------
# Helpers
# ---------------------------------------------------------------------------

def _json(data, status=200):
    body = json.dumps(data)
    return body, status, {"Content-Type": "application/json",
                          "Cache-Control": "no-store"}


def _error(msg, status=400):
    return _json({"error": msg}, status)


def _serve_file(filename, content_type):
    for prefix in ("/web/", "/"):
        path = prefix + filename
        try:
            os.stat(path)
            with open(path, "r") as f:
                body = f.read()
            return body, 200, {"Content-Type": content_type,
                               "Cache-Control": "no-cache"}
        except OSError:
            continue
    return _error("Not found", 404)


def _file_exists(path):
    try:
        os.stat(path)
        return True
    except OSError:
        return False


# ---------------------------------------------------------------------------
# Static files
# ---------------------------------------------------------------------------

@app.route("/", methods=["GET"])
async def index(request):
    return _serve_file("index.html", "text/html; charset=utf-8")


@app.route("/style.css", methods=["GET"])
async def css(request):
    return _serve_file("style.css", "text/css; charset=utf-8")


@app.route("/app.js", methods=["GET"])
async def js(request):
    return _serve_file("app.js", "application/javascript; charset=utf-8")


@app.route("/assets/<filename>", methods=["GET"])
async def serve_asset(request, filename):
    safe = filename.replace("..", "").replace("/", "").replace("\\", "")
    _mime = {".gif": "image/gif", ".png": "image/png", ".ico": "image/x-icon"}
    ext = ""
    parts = safe.rsplit(".", 1)
    if len(parts) == 2:
        ext = "." + parts[1]
    ct = _mime.get(ext, "application/octet-stream")
    for prefix in ("/web/assets/", "/assets/"):
        path = prefix + safe
        try:
            os.stat(path)
            with open(path, "rb") as f:
                body = f.read()
            return body, 200, {"Content-Type": ct, "Cache-Control": "public, max-age=3600"}
        except OSError:
            continue
    return _error("Not found", 404)


# ---------------------------------------------------------------------------
# /api/weight
# ---------------------------------------------------------------------------

@app.route("/api/weight", methods=["GET"])
async def get_weight(request):
    return _json(scale.get_weight_data())


# ---------------------------------------------------------------------------
# /api/tare
# ---------------------------------------------------------------------------

@app.route("/api/tare", methods=["POST"])
async def do_tare(request):
    scale.tare()
    return _json({"status": "ok"})


# ---------------------------------------------------------------------------
# /api/hold
# ---------------------------------------------------------------------------

@app.route("/api/hold", methods=["POST"])
async def do_hold(request):
    body = request.json or {}
    active = body.get("active", not scale.get_hold())
    scale.set_hold(active)
    return _json({"status": "ok", "hold": active})


# ---------------------------------------------------------------------------
# /api/calibrate
# ---------------------------------------------------------------------------

@app.route("/api/calibrate", methods=["POST"])
async def do_calibrate(request):
    body = request.json
    if not body or "weight_g" not in body:
        return _error("Provide weight_g (known weight in grams).")
    weight_g = float(body["weight_g"])
    if weight_g <= 0:
        return _error("weight_g must be positive.")
    ok, reason = scale.calibrate(weight_g)
    if not ok:
        return _error("Calibration failed: " + reason)
    return _json({"status": "ok",
                  "cal_factor": config_manager.get_config().get("cal_factor", 1.0)})


# ---------------------------------------------------------------------------
# /api/debug
# ---------------------------------------------------------------------------

@app.route("/api/debug", methods=["GET"])
async def get_debug(request):
    return _json(scale.get_debug_data())


# ---------------------------------------------------------------------------
# /api/config
# ---------------------------------------------------------------------------

@app.route("/api/config", methods=["GET"])
async def get_config(request):
    cfg = config_manager.get_config()
    wifi = config_manager.get_wifi()
    import network
    wlan = network.WLAN(network.STA_IF)
    ip = wlan.ifconfig()[0] if wlan.isconnected() else ""
    return _json({
        "units":         cfg.get("units", "kg"),
        "cal_factor":    cfg.get("cal_factor", 1.0),
        "keglevel_url":  cfg.get("keglevel_url", ""),
        "version":       FIRMWARE_VERSION,
        "build_date":    BUILD_DATE,
        "uptime_s":      time.ticks_diff(time.ticks_ms(), _boot_ticks) // 1000,
        "wifi_ssid":     wifi.get("ssid", ""),
        "wifi_ip":       ip,
        "wifi_mode":     wifi.get("mode", "sta"),
    })


@app.route("/api/config", methods=["PUT"])
async def put_config(request):
    body = request.json
    if not isinstance(body, dict):
        return _error("Body must be a JSON object.")
    patch = {}
    if "units" in body:
        u = body["units"]
        if u in ("kg", "lb", "lb_oz"):
            patch["units"] = u
    if "keglevel_url" in body:
        patch["keglevel_url"] = str(body["keglevel_url"]).strip()
    if patch:
        config_manager.update_config(patch)
    return _json({"status": "ok", "config": config_manager.get_config()})


# ---------------------------------------------------------------------------
# /api/version
# ---------------------------------------------------------------------------

@app.route("/api/version", methods=["GET"])
async def get_version(request):
    return _json({"version": FIRMWARE_VERSION, "build_date": BUILD_DATE})


# ---------------------------------------------------------------------------
# /api/profiles
# ---------------------------------------------------------------------------

@app.route("/api/profiles", methods=["GET"])
async def get_profiles(request):
    return _json(config_manager.get_profiles())


@app.route("/api/profiles", methods=["POST"])
async def create_profile(request):
    body = request.json
    if not isinstance(body, dict):
        return _error("Body must be a JSON object.")
    profile = config_manager.create_profile(body)
    return _json(profile, 201)


@app.route("/api/profiles/<profile_id>", methods=["PUT"])
async def update_profile(request, profile_id):
    body = request.json
    if not isinstance(body, dict):
        return _error("Body must be a JSON object.")
    result = config_manager.update_profile(profile_id, body)
    if result is None:
        return _error("Profile not found.", 404)
    return _json(result)


@app.route("/api/profiles/<profile_id>", methods=["DELETE"])
async def delete_profile(request, profile_id):
    if config_manager.delete_profile(profile_id):
        return _json({"status": "ok"})
    return _error("Profile not found.", 404)


# ---------------------------------------------------------------------------
# /api/keglevel/kegs  -  proxy to KegLevel Pico
# ---------------------------------------------------------------------------

def _http_request(method, url, body=None):
    """Minimal HTTP client for MicroPython (no urequests dependency)."""
    import socket
    proto, _, host_port, *path_parts = url.split("/", 3)
    path = "/" + (path_parts[0] if path_parts else "")
    if ":" in host_port:
        host, port = host_port.split(":", 1)
        port = int(port)
    else:
        host, port = host_port, 80

    addr = socket.getaddrinfo(host, port)[0][-1]
    s = socket.socket()
    s.settimeout(5)
    s.connect(addr)

    payload = json.dumps(body).encode() if body else None
    req = "{} {} HTTP/1.0\r\nHost: {}\r\n".format(method, path, host)
    if payload:
        req += "Content-Type: application/json\r\nContent-Length: {}\r\n".format(len(payload))
    req += "\r\n"
    s.send(req.encode())
    if payload:
        s.send(payload)

    resp = b""
    while True:
        chunk = s.recv(2048)
        if not chunk:
            break
        resp += chunk
    s.close()

    header_end = resp.find(b"\r\n\r\n")
    if header_end < 0:
        raise OSError("Invalid HTTP response")
    status_line = resp[:resp.find(b"\r\n")].decode()
    status_code = int(status_line.split(" ", 2)[1])
    body_bytes = resp[header_end + 4:]
    return status_code, json.loads(body_bytes)


@app.route("/api/keglevel/kegs", methods=["GET"])
async def proxy_list_kegs(request):
    cfg = config_manager.get_config()
    url = cfg.get("keglevel_url", "").rstrip("/")
    if not url:
        return _error("keglevel_url not configured.", 400)
    try:
        code, data = _http_request("GET", url + "/api/kegs")
        return _json(data, code)
    except Exception as e:
        return _error("KegLevel unreachable: " + str(e), 502)


@app.route("/api/keglevel/kegs/<keg_id>", methods=["PUT"])
async def proxy_update_keg(request, keg_id):
    cfg = config_manager.get_config()
    url = cfg.get("keglevel_url", "").rstrip("/")
    if not url:
        return _error("keglevel_url not configured.", 400)
    body = request.json
    if not isinstance(body, dict):
        return _error("Body must be a JSON object.")
    try:
        code, data = _http_request("PUT", url + "/api/kegs/" + keg_id, body)
        return _json(data, code)
    except Exception as e:
        return _error("KegLevel unreachable: " + str(e), 502)


# ---------------------------------------------------------------------------
# /api/update  -  OTA firmware update
# ---------------------------------------------------------------------------

_OTA_MANIFEST = "ota_manifest.json"


@app.route("/api/ota/manifest", methods=["GET"])
async def get_ota_manifest(request):
    if _file_exists(_OTA_MANIFEST):
        try:
            with open(_OTA_MANIFEST, "r") as f:
                return _json(json.load(f))
        except Exception:
            pass
    return _json({})


@app.route("/api/ota/manifest", methods=["PUT"])
async def put_ota_manifest(request):
    try:
        body = request.json
        with open(_OTA_MANIFEST, "w") as f:
            json.dump(body, f)
        return _json({"status": "ok"})
    except Exception as e:
        return _error(str(e))


@app.route("/api/update", methods=["POST"])
async def ota_update(request):
    """Write a file to flash for OTA updates."""
    try:
        gc.collect()
        body = request.json
        if not isinstance(body, dict):
            return _error("Body must be a JSON object.")

        filename = body.get("filename", "").strip().replace("\\", "/")
        content  = body.get("content",  "")
        reboot   = body.get("reboot",   False)
        append   = body.get("append",   False)

        _allowed_ext = (".py", ".html", ".css", ".js")
        if not any(filename.endswith(ext) for ext in _allowed_ext):
            return _error("File type not allowed.")
        if filename.startswith("/") or ".." in filename:
            return _error("Invalid path.")

        if not append and "/" in filename:
            acc = []
            for part in filename.split("/")[:-1]:
                acc.append(part)
                dirpath = "/".join(acc)
                try:
                    os.mkdir(dirpath)
                except OSError:
                    pass

        mode = "a" if append else "w"
        with open(filename, mode) as f:
            f.write(content)

        if not append:
            gz_stale = filename + ".gz"
            if _file_exists(gz_stale):
                try:
                    os.remove(gz_stale)
                except OSError:
                    pass

        print("[OTA] {} {} ({} bytes)".format(
            "Appended" if append else "Written", filename, len(content)))

        if reboot:
            asyncio.create_task(_delayed_reset(1500))

        return _json({"status": "ok", "filename": filename,
                      "bytes": len(content), "rebooting": reboot})
    except Exception as e:
        print("[OTA] Error: {}: {}".format(type(e).__name__, e))
        return _error("{}: {}".format(type(e).__name__, e))


async def _delayed_reset(ms):
    await asyncio.sleep_ms(ms)
    machine.reset()


# ---------------------------------------------------------------------------
# Error handlers
# ---------------------------------------------------------------------------

@app.errorhandler(404)
async def not_found(request):
    return _error("Not found.", 404)


@app.errorhandler(413)
async def too_large(request):
    return _error("Request too large.", 413)


@app.errorhandler(500)
async def internal_error(request):
    return _error("Internal server error.", 500)


# ---------------------------------------------------------------------------
# Start
# ---------------------------------------------------------------------------

async def start():
    print("[Server] Scale Brain v{} - starting on port 80".format(FIRMWARE_VERSION))
    await app.start_server(host="0.0.0.0", port=80)

/* Scale Brain — Frontend */

const KG_TO_LB = 2.20462;
const OTA_MANIFEST_URL =
  'https://raw.githubusercontent.com/keglevelmonitor/keglevelpico/main/ota/scalebrain/manifest.json';
const OTA_BUNDLE_URL =
  'https://raw.githubusercontent.com/keglevelmonitor/keglevelpico/main/ota/scalebrain/bundle.json';
const OTA_CHANGELOG_URL =
  'https://raw.githubusercontent.com/keglevelmonitor/keglevelpico/main/ota/scalebrain/changelog.json';

let currentUnit = 'kg';
let holdActive = false;
let profiles = [];
let selectedProfileId = '';
let editingProfileId = null;
let pollTimer = null;
let connected = false;

let kegs = [];
let selectedKegId = '';
let keglevelUrl = '';

let _otaManifest = null;
let _otaBundle = null;

// =========================================================================
// API helpers
// =========================================================================

async function apiFetch(path, opts = {}) {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), 4000);
  try {
    const resp = await fetch(path, { ...opts, signal: controller.signal });
    if (!resp.ok) throw new Error('HTTP ' + resp.status);
    return await resp.json();
  } finally {
    clearTimeout(timeout);
  }
}

// =========================================================================
// Screen / nav management (matches KegLevel pattern)
// =========================================================================

function showScreen(id) {
  document.querySelectorAll('.screen').forEach(el => el.classList.add('hidden'));
  const screen = document.getElementById(id);
  if (screen) screen.classList.remove('hidden');
}

function setActiveNav(activeId) {
  document.querySelectorAll('.top-nav .nav-btn').forEach(b => b.classList.remove('active'));
  const btn = document.getElementById(activeId);
  if (btn) btn.classList.add('active');
}

function navigateToScale() {
  showScreen('scale-screen');
  setActiveNav('btn-nav-scale');
  startPolling();
}

function navigateToSettings() {
  showScreen('settings-screen');
  setActiveNav('btn-nav-settings');
  stopPolling();
  setActiveSettingsTab('system');
  loadSystemInfo();
}

// -------------------------------------------------------------------------
// Settings sub-tabs
// -------------------------------------------------------------------------

function setActiveSettingsTab(tabId) {
  document.querySelectorAll('.settings-tab-btn').forEach(b => b.classList.remove('active'));
  document.querySelectorAll('.settings-pane').forEach(p => p.classList.remove('active'));
  const btn = document.querySelector('.settings-tab-btn[data-settings-tab="' + tabId + '"]');
  const pane = document.getElementById('settings-' + tabId);
  if (btn) btn.classList.add('active');
  if (pane) pane.classList.add('active');
  if (tabId === 'calibration') updateCalFormUnits();
  if (tabId === 'about') loadAboutInfo();
}

// =========================================================================
// Weight display
// =========================================================================

function formatWeight(data) {
  if (!data.sensor_ok) return { display: '\u2014', unit: '' };
  const kg = data.kg || 0;
  if (currentUnit === 'kg') return { display: kg.toFixed(2), unit: 'kg' };
  if (currentUnit === 'lb') return { display: (data.lb || 0).toFixed(2), unit: 'lb' };
  const lbOz = data.lb_oz || { lb: 0, oz: 0 };
  return { display: lbOz.lb + ' lb ' + lbOz.oz + ' oz', unit: '' };
}

function updateWeightDisplay(data) {
  const fmt = formatWeight(data);
  document.getElementById('weight-value').textContent = fmt.display;
  document.getElementById('weight-unit').textContent = fmt.unit;
  document.getElementById('stable-badge').classList.toggle('badge-hidden', !data.stable);
  const holdCaptured = data.hold && (data.hold_weight_kg || 0) > 0;
  document.getElementById('hold-badge').classList.toggle('badge-hidden', !holdCaptured);
  holdActive = data.hold;
  document.getElementById('btn-hold').classList.toggle('active', holdActive);
}

// =========================================================================
// Profile readout
// =========================================================================

function updateProfileReadout(weightData) {
  const readout = document.getElementById('profile-readout');
  if (!selectedProfileId || !weightData.sensor_ok) { readout.classList.add('hidden'); return; }
  const prof = profiles.find(p => p.id === selectedProfileId);
  if (!prof) { readout.classList.add('hidden'); return; }
  readout.classList.remove('hidden');
  const currentKg = weightData.kg || 0;
  const tareKg = prof.tare_weight_kg || 0;
  const capacityKg = prof.capacity_kg || 0;
  const remainingKg = Math.max(0, currentKg - tareKg);
  const pct = capacityKg > 0 ? Math.min(100, Math.max(0, (remainingKg / capacityKg) * 100)) : 0;
  let remainStr;
  if (currentUnit === 'kg') {
    remainStr = remainingKg.toFixed(2) + ' kg';
  } else if (currentUnit === 'lb') {
    remainStr = (remainingKg * KG_TO_LB).toFixed(2) + ' lb';
  } else {
    const totalOz = remainingKg * KG_TO_LB * 16;
    remainStr = Math.floor(totalOz / 16) + ' lb ' + Math.round(totalOz % 16) + ' oz';
  }
  document.getElementById('prof-remaining').textContent = remainStr;
  document.getElementById('prof-pct').textContent = pct.toFixed(0) + '%';
  document.getElementById('prof-bar-fill').style.width = pct.toFixed(1) + '%';
}

// =========================================================================
// Polling
// =========================================================================

async function poll() {
  try {
    const data = await apiFetch('/api/weight');
    updateWeightDisplay(data);
    updateProfileReadout(data);
    updateKegReadout(data);
    setConnected(true);
  } catch (_) {
    setConnected(false);
  }
}

function startPolling() {
  if (pollTimer) clearInterval(pollTimer);
  poll();
  pollTimer = setInterval(poll, 250);
}

function stopPolling() {
  if (pollTimer) { clearInterval(pollTimer); pollTimer = null; }
}

function setConnected(ok) {
  connected = ok;
  const dot = document.getElementById('status-dot');
  dot.className = 'header-status ' + (ok ? 'online' : 'offline');
}

// =========================================================================
// Tare / Hold actions
// =========================================================================

async function doTare() {
  try { await apiFetch('/api/tare', { method: 'POST' }); } catch (_) {}
}

async function doHold() {
  try {
    await apiFetch('/api/hold', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ active: !holdActive }),
    });
  } catch (_) {}
}

// =========================================================================
// Calibration (now in Settings)
// =========================================================================

function _calWeightGrams() {
  if (currentUnit === 'lb_oz') {
    const lb = parseFloat(document.getElementById('cal-weight-lb').value) || 0;
    const oz = parseFloat(document.getElementById('cal-weight-oz').value) || 0;
    return (lb + oz / 16) * 453.592;
  }
  const v = parseFloat(document.getElementById('cal-weight').value);
  if (!v || v <= 0) return 0;
  if (currentUnit === 'kg') return v * 1000;
  return v * 453.592;
}

async function doCalibrate() {
  const g = _calWeightGrams();
  if (g <= 0) { alert('Enter a valid calibration weight.'); return; }
  try {
    const result = await apiFetch('/api/calibrate', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ weight_g: g }),
    });
    document.getElementById('cal-factor').textContent =
      'Calibration factor: ' + (result.cal_factor || 0).toFixed(4);
    document.getElementById('cal-weight').value = '';
    document.getElementById('cal-weight-lb').value = '';
    document.getElementById('cal-weight-oz').value = '';
  } catch (e) {
    alert('Calibration failed: ' + (e.message || e));
  }
}

function updateCalFormUnits() {
  const singleRow = document.getElementById('cal-row-single');
  const lbozRow = document.getElementById('cal-row-lboz');
  if (currentUnit === 'lb_oz') {
    singleRow.classList.add('hidden');
    lbozRow.classList.remove('hidden');
  } else {
    singleRow.classList.remove('hidden');
    lbozRow.classList.add('hidden');
    document.getElementById('cal-unit-label').textContent = currentUnit === 'kg' ? 'kg' : 'lb';
  }
}

// =========================================================================
// Unit switching
// =========================================================================

function setUnit(unit) {
  currentUnit = unit;
  document.querySelectorAll('.unit-btn').forEach(btn => {
    btn.classList.toggle('active', btn.dataset.unit === unit);
  });
  updateFormUnits();
}

function updateFormUnits() {
  const label = currentUnit === 'kg' ? 'kg' : 'lb';
  ['prof-tare-unit', 'prof-full-unit', 'prof-cap-unit'].forEach(id => {
    const el = document.getElementById(id);
    if (el) el.textContent = label;
  });
  updateCalFormUnits();
  updateKegDisplay();
}

// =========================================================================
// Profiles CRUD
// =========================================================================

async function loadProfiles() {
  try {
    profiles = await apiFetch('/api/profiles');
    renderProfileSelect();
  } catch (_) {}
}

function renderProfileSelect() {
  const sel = document.getElementById('profile-select');
  const cur = sel.value;
  sel.innerHTML = '<option value="">-- No Profile --</option>';
  profiles.forEach(p => {
    const opt = document.createElement('option');
    opt.value = p.id;
    opt.textContent = p.name;
    sel.appendChild(opt);
  });
  if (cur && profiles.find(p => p.id === cur)) sel.value = cur;
  selectedProfileId = sel.value;
  document.getElementById('profile-readout').classList.toggle('hidden', !selectedProfileId);
}

function showProfileForm(profile) {
  editingProfileId = profile ? profile.id : null;
  const toKgOrLb = kg => currentUnit === 'kg' ? kg : kg * KG_TO_LB;
  document.getElementById('prof-name').value = profile ? profile.name : '';
  document.getElementById('prof-tare').value = profile ? toKgOrLb(profile.tare_weight_kg).toFixed(3) : '';
  document.getElementById('prof-full').value = profile ? toKgOrLb(profile.full_weight_kg).toFixed(3) : '';
  document.getElementById('prof-cap').value = profile ? toKgOrLb(profile.capacity_kg).toFixed(3) : '';
  document.getElementById('profile-form').classList.remove('hidden');
  updateFormUnits();
}

function hideProfileForm() {
  document.getElementById('profile-form').classList.add('hidden');
  editingProfileId = null;
}

async function saveProfile() {
  const fromDisplay = val => {
    const v = parseFloat(val) || 0;
    return currentUnit === 'kg' ? v : v / KG_TO_LB;
  };
  const data = {
    name:           document.getElementById('prof-name').value.trim() || 'Unnamed',
    tare_weight_kg: fromDisplay(document.getElementById('prof-tare').value),
    full_weight_kg: fromDisplay(document.getElementById('prof-full').value),
    capacity_kg:    fromDisplay(document.getElementById('prof-cap').value),
  };
  try {
    if (editingProfileId) {
      await apiFetch('/api/profiles/' + editingProfileId, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      });
    } else {
      await apiFetch('/api/profiles', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      });
    }
    hideProfileForm();
    await loadProfiles();
  } catch (e) { alert('Save failed: ' + (e.message || e)); }
}

async function deleteProfile() {
  if (!selectedProfileId) return;
  const prof = profiles.find(p => p.id === selectedProfileId);
  if (!confirm('Delete profile "' + (prof ? prof.name : '') + '"?')) return;
  try {
    await apiFetch('/api/profiles/' + selectedProfileId, { method: 'DELETE' });
    selectedProfileId = '';
    await loadProfiles();
  } catch (e) { alert('Delete failed: ' + (e.message || e)); }
}

async function setProfileWeight(field) {
  if (!selectedProfileId) return;
  try {
    const data = await apiFetch('/api/weight');
    if (!data.sensor_ok) { alert('Scale not ready.'); return; }
    const kg = data.kg || 0;
    const patch = {};
    if (field === 'full') {
      const prof = profiles.find(p => p.id === selectedProfileId);
      patch.full_weight_kg = kg;
      patch.capacity_kg = Math.max(0, kg - (prof ? prof.tare_weight_kg : 0));
    } else {
      patch.tare_weight_kg = kg;
      const prof = profiles.find(p => p.id === selectedProfileId);
      if (prof && prof.full_weight_kg > 0) patch.capacity_kg = Math.max(0, prof.full_weight_kg - kg);
    }
    await apiFetch('/api/profiles/' + selectedProfileId, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(patch),
    });
    await loadProfiles();
  } catch (e) { alert('Failed: ' + (e.message || e)); }
}

