async function loadKegs() {
  const statusEl = document.getElementById('keg-status');
  if (!keglevelUrl) {
    statusEl.textContent = 'Set KegLevel URL in Settings > System.';
    kegs = [];
    renderKegSelect();
    return;
  }
  statusEl.textContent = 'Loading kegs...';
  try {
    kegs = await apiFetch('/api/keglevel/kegs');
    statusEl.textContent = kegs.length + ' keg(s) loaded from KegLevel.';
    renderKegSelect();
  } catch (e) {
    statusEl.textContent = 'Failed to reach KegLevel: ' + (e.message || e);
    kegs = [];
    renderKegSelect();
  }
}

function renderKegSelect() {
  const sel = document.getElementById('keg-select');
  const cur = sel.value;
  sel.innerHTML = '<option value="">-- No Keg --</option>';
  kegs.forEach(k => {
    const opt = document.createElement('option');
    opt.value = k.id;
    opt.textContent = k.name || k.title || k.id;
    sel.appendChild(opt);
  });
  if (cur && kegs.find(k => k.id === cur)) sel.value = cur;
  selectedKegId = sel.value;
  document.getElementById('keg-readout').classList.toggle('hidden', !selectedKegId);
  updateKegDisplay();
}

function updateKegDisplay() {
  if (!selectedKegId) return;
  const keg = kegs.find(k => k.id === selectedKegId);
  if (!keg) return;
  const tare = keg.tare_weight_kg || 0;
  const full = keg.starting_total_weight_kg || 0;
  if (currentUnit === 'kg') {
    document.getElementById('keg-tare-val').textContent = tare.toFixed(2) + ' kg';
    document.getElementById('keg-full-val').textContent = full.toFixed(2) + ' kg';
  } else {
    document.getElementById('keg-tare-val').textContent = (tare * KG_TO_LB).toFixed(2) + ' lb';
    document.getElementById('keg-full-val').textContent = (full * KG_TO_LB).toFixed(2) + ' lb';
  }
}

function updateKegReadout(weightData) {
  if (!selectedKegId || !weightData.sensor_ok) return;
}

async function setKegWeight(field) {
  if (!selectedKegId) return;
  try {
    const data = await apiFetch('/api/weight');
    if (!data.sensor_ok) { alert('Scale not ready.'); return; }
    const kg = data.kg || 0;
    const patch = {};
    if (field === 'tare') {
      patch.tare_weight_kg = kg;
    } else {
      patch.starting_total_weight_kg = kg;
    }
    await apiFetch('/api/keglevel/kegs/' + selectedKegId, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(patch),
    });
    const keg = kegs.find(k => k.id === selectedKegId);
    if (keg) Object.assign(keg, patch);
    updateKegDisplay();
    const lbl = field === 'tare' ? 'Tare' : 'Full';
    document.getElementById('keg-status').textContent = lbl + ' weight saved to KegLevel.';
  } catch (e) {
    alert('Failed to update KegLevel: ' + (e.message || e));
  }
}

