  font-size: 12px;
  color: #777;
  margin-bottom: 8px;
}

/* ------------------------------------------------------------------ */
/* Settings screen (matches KegLevel)                                 */
/* ------------------------------------------------------------------ */
.settings-header {
  padding: 16px;
  background: #141414;
  border-bottom: 1px solid #222;
}

.settings-header h2 {
  margin: 0;
  font-size: 20px;
  font-weight: 700;
  color: #ffa500;
}

.settings-tabs {
  display: flex;
  gap: 4px;
  padding: 10px 16px;
  background: #1a1a1a;
  flex-wrap: wrap;
}

.settings-tab-btn {
  padding: 10px 16px;
  font-size: 14px;
  font-weight: 700;
  color: #888;
  background: #252525;
  border: 1px solid #333;
  border-radius: 4px;
  cursor: pointer;
}

.settings-tab-btn:hover { color: #ccc; background: #333; }

.settings-tab-btn.active {
  color: #ffa500;
  background: #1a1a1a;
  border-color: #ffa500;
}

.settings-content {
  flex: 1;
  overflow-y: auto;
  padding: 16px;
}

.settings-pane { display: none; }
.settings-pane.active { display: block; }

/* System section rows */
.system-section {
  margin-bottom: 24px;
}

.system-section h3 {
  margin: 0 0 12px 0;
  font-size: 16px;
  color: #ffa500;
}

.system-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 8px 0;
  border-bottom: 1px solid #1e1e1e;
}

.system-label { font-size: 13px; color: #888; }
.system-value { font-size: 14px; color: #e0e0e0; font-variant-numeric: tabular-nums; }

.system-field-label {
  display: block;
  font-size: 13px;
  color: #888;
  margin: 12px 0 4px;
}

.system-input-row {
  display: flex;
  gap: 10px;
}

.system-input-row input {
  flex: 1;
  padding: 10px 12px;
  font-size: 14px;
  background: #1a1a1a;
  border: 1px solid #333;
  border-radius: 6px;
  color: #e0e0e0;
}

.system-hint {
  font-size: 12px;
  color: #555;
  margin-top: 4px;
}

/* Update actions */
.update-actions {
  display: flex;
  gap: 10px;
  margin: 12px 0;
}

.update-btn-reload {
  padding: 10px 16px;
  font-size: 13px;
  font-weight: 700;
  border: none;
  border-radius: 6px;
  cursor: pointer;
  background: #f59e0b;
  color: #1a1a1a;
  white-space: nowrap;
}

.update-btn-reload:hover:not(:disabled) { background: #fbbf24; }
.update-btn-reload:disabled { opacity: 0.5; cursor: not-allowed; }

.update-status {
  font-size: 13px;
  color: #888;
  margin-top: 8px;
}

.update-progress-text {
  font-size: 12px;
  color: #888;
  margin-top: 4px;
  text-align: center;
}

/* Changelog */
.changelog-list {
  max-height: 300px;
  overflow-y: auto;
}

.changelog-entry {
  padding: 8px 0;
  border-bottom: 1px solid #1e1e1e;
}

.changelog-entry-header {
  display: flex;
  justify-content: space-between;
  margin-bottom: 4px;
}

.changelog-ver { font-size: 13px; font-weight: 700; color: #ffa500; }
.changelog-date { font-size: 12px; color: #555; }
.changelog-notes { font-size: 13px; color: #aaa; line-height: 1.5; }

/* ------------------------------------------------------------------ */
/* About section                                                      */
/* ------------------------------------------------------------------ */
.about-section { margin-bottom: 24px; }

.about-support-row {
  display: flex;
  align-items: flex-start;
  gap: 24px;
}

.about-support-row > div { flex: 1; min-width: 0; }

.about-support-img {
  width: 140px;
  height: 140px;
  object-fit: contain;
  flex-shrink: 0;
}

.about-section h3 {
  margin: 0 0 8px 0;
  font-size: 16px;
  color: #ffa500;
}

.about-section p {
  margin: 0;
  font-size: 14px;
  color: #ccc;
  line-height: 1.5;
}

.about-section a { color: #93c5fd; text-decoration: none; }
.about-section a:hover { text-decoration: underline; }

/* ------------------------------------------------------------------ */
/* Footer                                                             */
/* ------------------------------------------------------------------ */
.main-footer {
  text-align: center;
  padding: 20px;
  font-size: 12px;
  color: #444;
}

/* ------------------------------------------------------------------ */
/* Responsive                                                         */
/* ------------------------------------------------------------------ */
@media (max-width: 380px) {
  .weight-value { font-size: 48px; }
  .action-btn { padding: 12px; font-size: 14px; }
  .settings-tab-btn { padding: 8px 10px; font-size: 12px; }
}
